import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSSecureExample {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handling user input by encoding it before outputting
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        try {
            out.println("<h1>Welcome, " + ESAPI.encoder().encodeForHTML(userInput) + "</h1>");
        } catch (EncodingException e) {
            // Handle encoding exception
            System.err.println("Error encoding user input: " + e.getMessage());
        }
        out.println("</body>");
        out.println("</html>");

        out.flush();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
